import { useEffect } from "react";

const CSS = "\n/* ============================================================\n   WAYPOINT & Co. \u2014 STAY\n   Phase Seven \u00b7 Belonging\n   Motion language: inward, spatial, grounded.\n   ============================================================ */\n\n:root{\n  --ivory:        #F1EEE7;\n  --ivory-deep:   #EAE5DA;\n  --linen:        #E6E0D2;\n  --limestone:    #D8CFC0;\n  --sand:         #C9B295;\n  --timber:       #8A6F52;\n  --charcoal:     #211F1B;\n  --charcoal-soft:#2B2822;\n  --forest:       #3A453B;\n  --forest-deep:  #2C352E;\n  --ocean-grey:   #7C8B8F;\n  --stone-tas:    #56534B;\n  --fire:         #A9703C;\n  --metal:        #B3B0A7;\n  --ink-soft:     #6D6A61;\n  --ink-on-dark:  #EDEAE1;\n\n  --serif: \"Instrument Serif\", Georgia, serif;\n  --sans:  \"Instrument Sans\", -apple-system, \"Helvetica Neue\", sans-serif;\n  --mono:  \"IBM Plex Mono\", \"SF Mono\", monospace;\n\n  --gutter: clamp(20px, 5vw, 72px);\n  --max: 1360px;\n  --ease: cubic-bezier(0.22, 1, 0.36, 1);\n}\n\n*{ margin:0; padding:0; box-sizing:border-box; }\nhtml{ scroll-behavior:smooth; }\nbody{\n  background: var(--ivory);\n  color: var(--charcoal);\n  font-family: var(--sans);\n  font-size: 16px;\n  line-height: 1.68;\n  -webkit-font-smoothing: antialiased;\n  overflow-x: hidden;\n}\n::selection{ background: var(--timber); color: var(--ivory); }\na{ color: inherit; text-decoration: none; }\nbutton{ font: inherit; color: inherit; background: none; border: none; cursor: pointer; }\n\n/* ---------- shared vocabulary ---------- */\n.wrap{ max-width: var(--max); margin: 0 auto; padding-left: var(--gutter); padding-right: var(--gutter); }\n\n.eyebrow{\n  font-family: var(--mono); font-size: 11px; font-weight: 400;\n  letter-spacing: 0.32em; text-transform: uppercase; color: var(--timber);\n}\n.dark .eyebrow{ color: var(--sand); }\n\n.display{ font-family: var(--serif); font-weight: 400; line-height: 1.07; letter-spacing: -0.01em; }\n\n.lede{ font-size: clamp(17px, 1.35vw, 20px); line-height: 1.78; color: var(--ink-soft); max-width: 56ch; }\n.dark .lede{ color: #BDB9AD; }\n\n.mono-note{\n  font-family: var(--mono); font-size: 11.5px; font-weight: 300;\n  letter-spacing: 0.08em; line-height: 1.9; color: var(--ink-soft);\n}\n.dark .mono-note{ color: #96938A; }\n\n.action{\n  display: inline-flex; align-items: center; gap: 14px;\n  font-size: 13px; font-weight: 500;\n  letter-spacing: 0.18em; text-transform: uppercase;\n  padding: 17px 30px;\n  border: 1px solid var(--charcoal);\n  transition: background .5s var(--ease), color .5s var(--ease);\n}\n.action .mark{ font-family: var(--mono); font-weight: 300; transition: transform .5s var(--ease); }\n.action:hover{ background: var(--charcoal); color: var(--ivory); }\n.action:hover .mark{ transform: translateX(4px); }\n.action.solid{ background: var(--charcoal); color: var(--ivory); }\n.action.solid:hover{ background: var(--timber); border-color: var(--timber); }\n.action.quiet{ border: none; padding: 6px 0; border-bottom: 1px solid var(--metal); }\n.action.quiet:hover{ background: none; color: var(--timber); border-bottom-color: var(--timber); }\n.dark .action{ border-color: var(--ink-on-dark); color: var(--ink-on-dark); }\n.dark .action:hover{ background: var(--ink-on-dark); color: var(--charcoal); }\n\na:focus-visible, button:focus-visible, summary:focus-visible{\n  outline: 2px solid var(--timber); outline-offset: 4px;\n}\n\n/* inward reveal \u2014 entering a space */\n.enter{\n  opacity: 0;\n  transform: scale(1.025);\n  clip-path: inset(5% 7% 5% 7%);\n  transition: opacity 1.1s var(--ease), transform 1.4s var(--ease), clip-path 1.4s var(--ease);\n}\n.enter.in{ opacity: 1; transform: scale(1); clip-path: inset(0 0 0 0); }\n.enter.d1{ transition-delay: .14s; }\n.enter.d2{ transition-delay: .28s; }\n.enter.d3{ transition-delay: .42s; }\n\n/* soft settle for text */\n.settle{\n  opacity: 0; transform: translateY(20px);\n  transition: opacity 1s var(--ease), transform 1.2s var(--ease);\n}\n.settle.in{ opacity: 1; transform: none; }\n.settle.d1{ transition-delay: .14s; }\n.settle.d2{ transition-delay: .28s; }\n.settle.d3{ transition-delay: .42s; }\n\n/* ============================================================\n   NAV\n   ============================================================ */\n.nav{\n  position: fixed; top: 0; left: 0; right: 0; z-index: 60;\n  display: flex; align-items: center; justify-content: space-between;\n  padding: 22px var(--gutter);\n  transition: background .5s var(--ease), box-shadow .5s var(--ease), padding .5s var(--ease);\n}\n.nav.scrolled{\n  background: rgba(241,238,231,0.93);\n  backdrop-filter: blur(12px);\n  padding-top: 14px; padding-bottom: 14px;\n  box-shadow: 0 1px 0 rgba(33,31,27,0.08);\n}\n.nav .wordmark{ font-family: var(--serif); font-size: 19px; letter-spacing: .04em; }\n.nav .wordmark span{ font-family: var(--mono); font-size: 10px; letter-spacing: .3em; color: var(--timber); display:block; margin-top: 1px; }\n.nav-links{ display: flex; gap: 34px; align-items: center; }\n.nav-links a{\n  font-family: var(--mono); font-size: 11px; letter-spacing: .28em; text-transform: uppercase;\n  color: var(--ink-soft); padding-bottom: 3px; border-bottom: 1px solid transparent;\n  transition: color .3s, border-color .3s;\n}\n.nav-links a:hover{ color: var(--charcoal); }\n.nav-links a.current{ color: var(--charcoal); border-bottom-color: var(--charcoal); }\n.nav-begin{\n  font-family: var(--mono); font-size: 11px; letter-spacing: .24em; text-transform: uppercase;\n  border: 1px solid var(--charcoal); padding: 10px 20px;\n  transition: background .4s var(--ease), color .4s var(--ease);\n}\n.nav-begin:hover{ background: var(--charcoal); color: var(--ivory); }\n.nav.on-dark:not(.scrolled){ color: var(--ink-on-dark); }\n.nav.on-dark:not(.scrolled) .nav-links a{ color: rgba(237,234,225,.7); }\n.nav.on-dark:not(.scrolled) .nav-links a:hover,\n.nav.on-dark:not(.scrolled) .nav-links a.current{ color: var(--ink-on-dark); border-bottom-color: var(--ink-on-dark); }\n.nav.on-dark:not(.scrolled) .nav-begin{ border-color: var(--ink-on-dark); }\n.nav.on-dark:not(.scrolled) .nav-begin:hover{ background: var(--ink-on-dark); color: var(--charcoal); }\n.nav.on-dark:not(.scrolled) .wordmark span{ color: var(--sand); }\n\n/* ============================================================\n   1 \u00b7 HERO \u2014 THE THRESHOLD\n   Walls part; the visitor enters a private world.\n   ============================================================ */\n.hero{\n  position: relative;\n  min-height: 100svh;\n  display: flex; align-items: flex-end;\n  color: var(--ink-on-dark);\n  background: var(--charcoal);\n  overflow: hidden;\n}\n/* the view beyond the threshold */\n.hero .view{\n  position: absolute; inset: 0;\n  background:\n    linear-gradient(180deg,\n      #A9B4B2 0%,\n      #C3C6BB 30%,\n      #7C8B8F 46%,     /* sea line */\n      #8E958C 52%,\n      #C9BBA4 70%,     /* limestone terrace */\n      #D8CFC0 86%,\n      #B7A98F 100%);\n}\n.hero .view::after{ /* light across the surface */\n  content:\"\"; position:absolute; inset:0;\n  background: linear-gradient(115deg, rgba(241,238,231,0.0) 30%, rgba(241,238,231,0.22) 48%, rgba(241,238,231,0.0) 62%);\n  animation: light-pass 18s var(--ease) infinite alternate;\n}\n@keyframes light-pass{\n  from{ transform: translateX(-8%); }\n  to{   transform: translateX(8%); }\n}\n/* threshold walls \u2014 part on arrival, a fine frame remains */\n.hero .wall{ position: absolute; top: 0; bottom: 0; background: var(--charcoal); z-index: 2; }\n.hero .wall.left{ left: 0; width: 38%; animation: part-left 2.4s var(--ease) .3s forwards; }\n.hero .wall.right{ right: 0; width: 38%; animation: part-right 2.4s var(--ease) .3s forwards; }\n.hero .lintel{\n  position:absolute; left:0; right:0; top:0; height: 26%;\n  background: var(--charcoal); z-index: 2;\n  animation: lift 2.4s var(--ease) .3s forwards;\n}\n@keyframes part-left{ to{ width: 4.5%; } }\n@keyframes part-right{ to{ width: 4.5%; } }\n@keyframes lift{ to{ height: 7%; } }\n.hero .sill{\n  position:absolute; left:0; right:0; bottom:0; height: 4.5%;\n  background: var(--charcoal); z-index: 2;\n}\n/* dark grade over the view for legibility */\n.hero .grade{\n  position:absolute; inset:0; z-index: 3; pointer-events:none;\n  background: linear-gradient(180deg, rgba(33,31,27,0.18) 0%, rgba(33,31,27,0.0) 40%, rgba(33,31,27,0.5) 100%);\n}\n.hero-inner{\n  position: relative; z-index: 4;\n  width: 100%;\n  padding-bottom: clamp(64px, 10vh, 120px);\n}\n.hero h1{\n  font-size: clamp(46px, 7.2vw, 104px);\n  max-width: 12ch;\n  text-shadow: 0 1px 26px rgba(33,31,27,0.25);\n}\n.hero .lede{ color: rgba(237,234,225,0.86); margin-top: 26px; max-width: 48ch; }\n.hero-actions{ display: flex; gap: 18px; margin-top: 44px; flex-wrap: wrap; }\n.hero .action{ border-color: rgba(237,234,225,0.9); color: var(--ink-on-dark); }\n.hero .action:hover{ background: var(--ink-on-dark); color: var(--charcoal); }\n.hero .action.solid{ background: rgba(237,234,225,0.96); color: var(--charcoal); border-color: transparent; }\n.hero .action.solid:hover{ background: var(--ivory); }\n.hero-ident{\n  position: absolute; right: calc(var(--gutter) + 1%); bottom: clamp(64px, 10vh, 120px);\n  text-align: right; z-index: 4;\n  font-family: var(--mono); font-size: 11px; font-weight: 300;\n  letter-spacing: .3em; line-height: 2.3; color: rgba(237,234,225,0.66);\n}\n.hero-ident b{ font-weight: 400; color: rgba(237,234,225,0.95); letter-spacing: .34em; }\n.hero .load{ opacity: 0; transform: translateY(24px); animation: settle-in 1.5s var(--ease) forwards; }\n.hero .load.l2{ animation-delay: .55s; }\n.hero .load.l3{ animation-delay: .85s; }\n.hero .load.l4{ animation-delay: 1.15s; }\n@keyframes settle-in{ to{ opacity: 1; transform: none; } }\n\n/* ============================================================\n   2 \u00b7 EDITORIAL INTRODUCTION\n   ============================================================ */\n.intro{ padding: clamp(96px, 14vh, 180px) 0 clamp(84px, 12vh, 160px); }\n.split{\n  display: grid; grid-template-columns: minmax(0, 1.05fr) minmax(0, 1fr);\n  gap: clamp(40px, 6vw, 110px); align-items: center;\n}\n.intro h2{ font-size: clamp(34px, 4.2vw, 62px); margin: 22px 0 30px; max-width: 14ch; }\n.intro .statement{\n  font-family: var(--serif); font-style: italic;\n  font-size: clamp(19px, 1.7vw, 24px); color: var(--timber);\n  margin-top: 34px; max-width: 32ch;\n}\n/* window elevation \u2014 drawn, lived-in */\n.window-figure svg{ display:block; width: 100%; height: auto; }\n.window-figure .fig-caption{\n  margin-top: 18px; display:flex; justify-content: space-between; gap: 16px; flex-wrap: wrap;\n}\n\n/* ============================================================\n   3 \u00b7 THE ARCHITECTURE OF BELONGING \u2014 STAY's navigation system\n   Thresholds and spaces, an architect's pencil interpreted editorially.\n   ============================================================ */\n.belonging{ background: var(--linen); padding: clamp(96px, 14vh, 180px) 0; }\n.belonging-head{ text-align: center; max-width: 660px; margin: 0 auto clamp(64px, 9vh, 120px); }\n.belonging-head h2{ font-size: clamp(32px, 3.8vw, 54px); margin-top: 20px; }\n.plan{\n  position: relative; max-width: 760px; margin: 0 auto;\n}\n/* the wall line */\n.plan-line{\n  position: absolute; left: 27px; top: 10px; bottom: 10px; width: 1px;\n  background: var(--metal);\n}\n.plan-line .pencil{\n  position: absolute; top: 0; left: 0; width: 100%; height: 0%;\n  background: var(--timber); transition: height .2s linear;\n}\n.space{\n  position: relative; display: grid;\n  grid-template-columns: 56px 200px minmax(0,1fr);\n  gap: clamp(20px, 3vw, 44px); align-items: start;\n  padding: 0 0 clamp(48px, 6.5vh, 76px);\n}\n.space:last-child{ padding-bottom: 0; }\n.space .glyph{ position: relative; z-index: 2; }\n.space .glyph svg{ display:block; width: 56px; height: 56px; background: var(--linen); }\n.space .sp-name{\n  font-family: var(--mono); font-size: 12px; letter-spacing: .38em;\n  text-transform: uppercase; color: var(--charcoal); padding-top: 16px;\n}\n.space .sp-anno{ display:block; margin-top: 8px; font-family: var(--mono); font-size: 10px; font-weight:300; letter-spacing: .16em; color: var(--ink-soft); }\n.space .sp-line{\n  font-family: var(--serif); font-size: clamp(21px, 2.3vw, 30px);\n  line-height: 1.32; max-width: 24ch; padding-top: 8px;\n}\n.plan-footnote{ text-align: center; margin-top: clamp(52px, 7vh, 84px); }\n\n/* ============================================================\n   4 \u00b7 FEATURED DESTINATIONS \u2014 three material worlds\n   ============================================================ */\n.dest-chapters{ padding: clamp(96px, 14vh, 180px) 0 0; }\n.dest-chapters-head{ max-width: 700px; margin-bottom: clamp(64px, 9vh, 110px); }\n.dest-chapters-head h2{ font-size: clamp(34px, 4.2vw, 60px); margin-top: 20px; }\n\n.dchapter{\n  display: grid; grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);\n  gap: clamp(36px, 5vw, 90px);\n  padding: clamp(64px, 8vh, 100px) 0;\n  border-top: 1px solid var(--metal);\n  align-items: center;\n}\n.dchapter:last-of-type{ border-bottom: 1px solid var(--metal); }\n.dchapter .material{\n  position: relative; aspect-ratio: 4 / 5; overflow: hidden;\n}\n.dchapter .material::before{ content:\"\"; position: absolute; inset: 0; }\n.dchapter .material::after{ /* interior frame \u2014 the view held in architecture */\n  content:\"\"; position:absolute; inset: 14px;\n  border: 1px solid rgba(241,238,231,0.55);\n  pointer-events: none;\n}\n.dchapter[data-tone=\"hamilton\"] .material::before{\n  background: linear-gradient(180deg, #BCC7C4 0%, #D5D4C6 34%, #7C8B8F 50%, #98A096 58%, #D8CFC0 82%, #C4B69C 100%);\n}\n.dchapter[data-tone=\"noosa\"] .material::before{\n  background: linear-gradient(180deg, #C7C4A8 0%, #A9B08C 32%, #7E9287 48%, #C9B295 72%, #B99F7C 100%);\n}\n.dchapter[data-tone=\"tasmania\"] .material::before{\n  background: linear-gradient(180deg, #3E4640 0%, #56534B 38%, #6E6759 58%, #8A6F52 80%, #A9703C 100%);\n}\n.dchapter .material .m-note{\n  position:absolute; left: 26px; bottom: 22px;\n  font-family: var(--mono); font-size: 10px; letter-spacing: .3em;\n  text-transform: uppercase; color: rgba(241,238,231,0.85);\n}\n.dchapter h3{ font-family: var(--serif); font-weight: 400; font-size: clamp(30px, 3.4vw, 48px); line-height: 1.1; }\n.dchapter .d-essence{\n  font-family: var(--serif); font-style: italic;\n  font-size: clamp(18px, 1.6vw, 23px); color: var(--ink-soft);\n  margin: 16px 0 26px; max-width: 30ch;\n}\n.dchapter .themes{\n  display: flex; flex-wrap: wrap; gap: 8px 0; max-width: 46ch;\n  font-family: var(--mono); font-size: 11px; font-weight: 300;\n  letter-spacing: .14em; text-transform: uppercase; color: var(--ink-soft);\n}\n.dchapter .themes span::after{ content: \"\u00b7\"; margin: 0 10px; color: var(--metal); }\n.dchapter .themes span:last-child::after{ content: \"\"; margin: 0; }\n.dchapter .services{\n  margin-top: 26px; font-family: var(--mono); font-size: 10.5px;\n  letter-spacing: .3em; text-transform: uppercase; color: var(--timber);\n}\n.dchapter .action{ margin-top: 34px; }\n.dchapter:nth-child(even) .material{ order: 2; }\n\n/* ============================================================\n   5 \u00b7 CURATED RESIDENCES \u2014 one at a time\n   ============================================================ */\n.residences{ background: var(--ivory-deep); padding: clamp(96px, 14vh, 180px) 0; }\n.residences-head{ max-width: 720px; margin-bottom: clamp(56px, 8vh, 100px); }\n.residences-head h2{ font-size: clamp(34px, 4.2vw, 60px); margin: 20px 0 26px; }\n\n.residence{\n  border-top: 1px solid var(--metal);\n  padding: clamp(56px, 7.5vh, 92px) 0;\n}\n.residence:last-of-type{ border-bottom: 1px solid var(--metal); }\n.res-grid{\n  display: grid; grid-template-columns: minmax(0, 1.15fr) minmax(0, 1fr);\n  gap: clamp(36px, 5vw, 90px); align-items: start;\n}\n.res-media{ position: relative; aspect-ratio: 16 / 10; overflow: hidden; }\n.res-media::before{ content:\"\"; position:absolute; inset:0; }\n.residence[data-tone=\"hamilton\"] .res-media::before{\n  background: linear-gradient(165deg, #D5D4C6 0%, #BCC7C4 34%, #7C8B8F 62%, #D8CFC0 100%);\n}\n.residence[data-tone=\"noosa\"] .res-media::before{\n  background: linear-gradient(165deg, #C9C6AB 0%, #A9B08C 40%, #C9B295 78%, #E6E0D2 100%);\n}\n.residence[data-tone=\"tasmania\"] .res-media::before{\n  background: linear-gradient(165deg, #3E4640 0%, #56534B 44%, #8A6F52 82%, #6E6759 100%);\n}\n.res-media .placeholder{\n  position: absolute; inset: 16px; border: 1px dashed rgba(241,238,231,0.5);\n  display: flex; align-items: flex-end; padding: 20px;\n}\n.res-media .placeholder span{\n  font-family: var(--mono); font-size: 10px; letter-spacing: .26em;\n  text-transform: uppercase; color: rgba(241,238,231,0.85); line-height: 2;\n}\n.res-body .r-dest{ margin-bottom: 16px; }\n.res-body h3{ font-family: var(--serif); font-weight: 400; font-size: clamp(28px, 3vw, 42px); line-height: 1.1; }\n.res-body .r-essence{\n  font-family: var(--serif); font-style: italic;\n  font-size: clamp(17px, 1.5vw, 21px); color: var(--ink-soft);\n  margin: 14px 0 24px; max-width: 34ch;\n}\n.res-facts{\n  display: grid; grid-template-columns: 1fr 1fr; gap: 18px 32px; margin: 26px 0;\n}\n.res-facts .f-label{\n  font-family: var(--mono); font-size: 10px; letter-spacing: .3em;\n  text-transform: uppercase; color: var(--timber); margin-bottom: 6px;\n}\n.res-facts p{ font-size: 14.5px; color: var(--ink-soft); line-height: 1.6; }\n.res-with{\n  margin: 26px 0 8px; padding-top: 22px; border-top: 1px solid var(--metal);\n}\n.res-with .f-label{\n  font-family: var(--mono); font-size: 10px; letter-spacing: .3em;\n  text-transform: uppercase; color: var(--timber); margin-bottom: 12px;\n}\n.res-with ul{ list-style: none; display: flex; flex-wrap: wrap; gap: 8px 0; font-size: 14px; color: var(--ink-soft); }\n.res-with li::after{ content: \"\u00b7\"; margin: 0 10px; color: var(--metal); }\n.res-with li:last-child::after{ content: \"\"; margin: 0; }\n.res-attr{ margin-top: 18px; }\n.res-body .action{ margin-top: 28px; }\n\n/* ============================================================\n   6 \u00b7 THE RHYTHM OF A STAY\n   ============================================================ */\n.rhythm{ padding: clamp(96px, 14vh, 180px) 0; }\n.rhythm-head{ text-align: center; max-width: 620px; margin: 0 auto clamp(64px, 9vh, 110px); }\n.rhythm-head h2{ font-size: clamp(32px, 3.8vw, 54px); margin-top: 20px; }\n.day{\n  max-width: 680px; margin: 0 auto;\n}\n.moment{\n  display: grid; grid-template-columns: 140px minmax(0,1fr);\n  gap: clamp(24px, 4vw, 56px); align-items: baseline;\n  padding: clamp(26px, 3.4vh, 40px) 0;\n  border-top: 1px solid var(--metal);\n}\n.moment:last-child{ border-bottom: 1px solid var(--metal); }\n.moment .m-time{\n  font-family: var(--mono); font-size: 11px; letter-spacing: .38em;\n  text-transform: uppercase; color: var(--timber);\n}\n.moment .m-line{ font-family: var(--serif); font-size: clamp(21px, 2.2vw, 29px); line-height: 1.3; }\n.moment .m-detail{\n  display: block; margin-top: 10px;\n  font-size: 13.5px; color: var(--ink-soft); font-family: var(--sans); line-height: 1.7; max-width: 44ch;\n}\n.rhythm-footnote{ text-align: center; margin-top: clamp(44px, 6vh, 64px); }\n\n/* ============================================================\n   7 \u00b7 CONNECTED JOURNEYS\n   ============================================================ */\n.journeys{ background: var(--linen); padding: clamp(96px, 14vh, 180px) 0; }\n.journeys-head{ max-width: 700px; margin-bottom: clamp(56px, 8vh, 90px); }\n.journeys-head h2{ font-size: clamp(34px, 4.2vw, 60px); margin-top: 20px; }\n.journey-grid{ display: grid; grid-template-columns: repeat(3, minmax(0,1fr)); gap: clamp(20px, 2.6vw, 40px); }\n.journey{\n  background: var(--ivory);\n  border: 1px solid rgba(179,176,167,0.65);\n  padding: clamp(28px, 3vw, 44px);\n  display: flex; flex-direction: column;\n  transition: transform .8s var(--ease), box-shadow .8s var(--ease);\n}\n.journey:hover{ transform: translateY(-8px); box-shadow: 0 26px 60px -32px rgba(33,31,27,0.3); }\n.journey .j-kicker{ margin-bottom: 22px; }\n.journey h3{ font-family: var(--serif); font-weight: 400; font-size: clamp(24px, 2.2vw, 32px); line-height: 1.12; margin-bottom: 26px; }\n.j-course{ position: relative; padding-left: 24px; flex: 1; }\n.j-course::before{\n  content:\"\"; position:absolute; left:3px; top: 7px; bottom: 7px; width:1px; background: var(--metal);\n}\n.j-step{ position: relative; padding-bottom: 18px; }\n.j-step:last-child{ padding-bottom: 0; }\n.j-step::before{\n  content:\"\"; position:absolute; left:-24px; top: 6px;\n  width: 7px; height: 7px; border-radius: 50%;\n  border: 1px solid var(--timber); background: var(--ivory);\n}\n.j-step .s-kind{ font-family: var(--mono); font-size: 9.5px; letter-spacing: .3em; text-transform: uppercase; color: var(--timber); }\n.j-step .s-text{ font-size: 14.5px; margin-top: 3px; line-height: 1.55; }\n.journey .j-actions{\n  margin-top: 34px; padding-top: 24px; border-top: 1px solid rgba(179,176,167,0.55);\n  display: flex; flex-direction: column; gap: 12px; align-items: flex-start;\n}\n\n/* ============================================================\n   8 \u00b7 PRIVATE SERVICES \u2014 quiet, text-led\n   ============================================================ */\n.services{ padding: clamp(96px, 14vh, 180px) 0; }\n.services .split{ align-items: start; }\n.services h2{ font-size: clamp(32px, 3.8vw, 54px); margin: 20px 0 26px; max-width: 15ch; }\n.service-list{ border-top: 1px solid var(--metal); }\n.service-row{\n  display: grid; grid-template-columns: minmax(0,1fr) auto;\n  gap: 24px; align-items: baseline;\n  padding: 17px 0; border-bottom: 1px solid var(--metal);\n  font-size: 15.5px;\n}\n.service-row .s-note{\n  font-family: var(--mono); font-size: 10px; font-weight: 300;\n  letter-spacing: .2em; text-transform: uppercase; color: var(--ink-soft);\n}\n.services .caveat{ margin-top: 26px; }\n\n/* ============================================================\n   9 \u00b7 WHY WAYPOINT \u2014 behind the stay (forest, warmer than AIR)\n   ============================================================ */\n.dark{ color: var(--ink-on-dark); }\n.why{ background: var(--forest-deep); padding: clamp(104px, 15vh, 190px) 0; position: relative; overflow: hidden; }\n.why::before{\n  content:\"\"; position:absolute; inset:0; pointer-events:none;\n  background:\n    radial-gradient(80% 55% at 85% 0%, rgba(201,178,149,0.09), transparent 62%),\n    radial-gradient(70% 45% at 8% 100%, rgba(169,112,60,0.10), transparent 58%);\n}\n.why .wrap{ position: relative; }\n.why h2{ font-size: clamp(34px, 4.4vw, 64px); margin: 22px 0 26px; max-width: 15ch; }\n.principles{\n  display: grid; grid-template-columns: 1fr 1fr; gap: 1px;\n  background: rgba(230,224,210,0.18);\n  border: 1px solid rgba(230,224,210,0.18);\n  margin-top: clamp(56px, 7vh, 90px);\n}\n.principle{ background: var(--forest-deep); padding: clamp(30px, 3.4vw, 52px); }\n.principle .p-code{\n  font-family: var(--mono); font-size: 10.5px; letter-spacing: .34em;\n  text-transform: uppercase; color: var(--sand); margin-bottom: 20px;\n}\n.principle p{ font-family: var(--serif); font-size: clamp(19px, 1.8vw, 25px); line-height: 1.42; color: var(--ink-on-dark); max-width: 28ch; }\n\n/* ============================================================\n   10/11 \u00b7 BEGIN YOUR STAY \u2014 dusk, calm, complete\n   ============================================================ */\n.begin{\n  position: relative;\n  padding: clamp(130px, 20vh, 240px) 0;\n  text-align: center;\n  color: var(--ink-on-dark);\n  background:\n    linear-gradient(180deg,\n      #2B2822 0%,\n      #3A3A33 30%,\n      #56534B 52%,\n      #8A6F52 76%,\n      #A9703C 92%,\n      #B4763F 100%);\n  overflow: hidden;\n}\n.begin::before{ /* open doorway of light at centre */\n  content:\"\"; position:absolute; left:50%; bottom:0; transform: translateX(-50%);\n  width: min(280px, 40vw); height: 62%;\n  background: linear-gradient(180deg, rgba(241,238,231,0.0), rgba(241,238,231,0.14) 55%, rgba(241,238,231,0.26));\n  border-left: 1px solid rgba(241,238,231,0.35);\n  border-right: 1px solid rgba(241,238,231,0.35);\n  border-top: 1px solid rgba(241,238,231,0.35);\n}\n.begin .wrap{ position: relative; }\n.begin h2{ font-size: clamp(38px, 5.4vw, 84px); max-width: 13ch; margin: 24px auto 26px; }\n.begin .lede{ margin: 0 auto 46px; color: rgba(237,234,225,0.85); }\n.begin-actions{ display:flex; gap: 18px; justify-content: center; flex-wrap: wrap; }\n.begin .action{ border-color: rgba(237,234,225,0.9); color: var(--ink-on-dark); }\n.begin .action:hover{ background: var(--ink-on-dark); color: var(--charcoal); }\n.begin .action.solid{ background: rgba(237,234,225,0.96); color: var(--charcoal); border-color: transparent; }\n.begin .action.solid:hover{ background: var(--ivory); }\n.begin .closing{ margin-top: clamp(48px, 7vh, 72px); }\n.begin .closing .mono-note{ color: rgba(237,234,225,0.55); letter-spacing: .32em; }\n\n/* ============================================================\n   FOOTER\n   ============================================================ */\n.footer{ background: var(--charcoal); color: var(--ink-on-dark); padding: clamp(64px, 8vh, 100px) 0 40px; }\n.footer-top{\n  display: grid; grid-template-columns: minmax(0,1.4fr) repeat(3, minmax(0,1fr));\n  gap: clamp(32px, 4vw, 64px);\n  padding-bottom: clamp(44px, 5vh, 64px);\n  border-bottom: 1px solid rgba(179,176,167,0.22);\n}\n.footer .wordmark{ font-family: var(--serif); font-size: 22px; }\n.footer .wordmark span{ font-family: var(--mono); font-size: 10px; letter-spacing: .3em; color: var(--sand); display: block; margin-top: 4px; }\n.footer h4{ font-family: var(--mono); font-size: 10.5px; font-weight: 400; letter-spacing: .32em; text-transform: uppercase; color: var(--sand); margin-bottom: 20px; }\n.footer ul{ list-style: none; display: flex; flex-direction: column; gap: 12px; }\n.footer ul a{ font-size: 14px; color: #BDB9AD; transition: color .3s; }\n.footer ul a:hover{ color: var(--ink-on-dark); }\n.footer-bottom{ display: flex; justify-content: space-between; gap: 24px; flex-wrap: wrap; padding-top: 32px; }\n.footer-bottom .mono-note{ color: #7A776E; }\n\n/* ============================================================\n   ADD STAY TO JOURNEY \u2014 persistent quiet control\n   ============================================================ */\n.add-stay{\n  position: fixed; right: 26px; bottom: 26px; z-index: 70;\n  display: inline-flex; align-items: center; gap: 12px;\n  font-family: var(--mono); font-size: 10.5px; letter-spacing: .26em; text-transform: uppercase;\n  background: rgba(241,238,231,0.94); backdrop-filter: blur(10px);\n  color: var(--charcoal);\n  border: 1px solid var(--metal);\n  padding: 13px 20px;\n  transition: background .4s var(--ease), color .4s var(--ease), border-color .4s var(--ease), transform .6s var(--ease);\n  opacity: 0; transform: translateY(16px); pointer-events: none;\n}\n.add-stay.visible{ opacity: 1; transform: translateY(0); pointer-events: auto; }\n.add-stay .dot{ width: 7px; height: 7px; border-radius: 50%; border: 1px solid var(--timber); transition: background .4s; }\n.add-stay:hover{ border-color: var(--charcoal); }\n.add-stay.added{ background: var(--charcoal); color: var(--ivory); border-color: var(--charcoal); }\n.add-stay.added .dot{ background: var(--sand); border-color: var(--sand); }\n\n/* ============================================================\n   REDUCED MOTION\n   ============================================================ */\n@media (prefers-reduced-motion: reduce){\n  html{ scroll-behavior: auto; }\n  *, *::before, *::after{ animation: none !important; transition: none !important; }\n  .enter, .settle, .hero .load{ opacity: 1; transform: none; clip-path: none; }\n  .hero .wall.left, .hero .wall.right{ width: 4.5%; }\n  .hero .lintel{ height: 7%; }\n  .plan-line .pencil{ height: 100% !important; }\n}\n\n/* ============================================================\n   MOBILE \u2014 vertical residence log\n   ============================================================ */\n@media (max-width: 980px){\n  .split{ grid-template-columns: 1fr; }\n  .dchapter{ grid-template-columns: 1fr; }\n  .dchapter:nth-child(even) .material{ order: 0; }\n  .dchapter .material{ aspect-ratio: 4 / 3; }\n  .res-grid{ grid-template-columns: 1fr; }\n  .space{ grid-template-columns: 56px minmax(0,1fr); }\n  .space .sp-line{ grid-column: 2; padding-top: 12px; }\n  .journey-grid{ grid-template-columns: 1fr; }\n  .principles{ grid-template-columns: 1fr; }\n  .moment{ grid-template-columns: 96px minmax(0,1fr); }\n  .footer-top{ grid-template-columns: 1fr 1fr; }\n  .hero-ident{ display: none; }\n  .nav-links{ display: none; }\n  .hero .wall.left, .hero .wall.right{ animation-name: part-left-m; }\n  @keyframes part-left-m{ to{ width: 3%; } }\n}\n@media (max-width: 560px){\n  .footer-top{ grid-template-columns: 1fr; }\n  .res-facts{ grid-template-columns: 1fr; }\n  .add-stay{ right: 16px; bottom: 16px; }\n}\n";
const HTML = "<!-- ============ NAV ============ -->\n<nav class=\"nav on-dark\" id=\"nav\">\n  <a href=\"/\" class=\"wordmark\">WAYPOINT &amp; Co.<span>SEA \u00b7 STAY \u00b7 AIR</span></a>\n  <div class=\"nav-links\">\n    <a href=\"/sea\">Sea</a>\n    <a href=\"/stay\" class=\"current\" aria-current=\"page\">Stay</a>\n    <a href=\"/air\">Air</a>\n    <a href=\"/journeys\">Journeys</a>\n  </div>\n  <a class=\"nav-begin\" href=\"/begin?mode=stay&src=stay-nav\">Begin</a>\n</nav>\n\n<!-- ============ 1 \u00b7 HERO \u2014 THE THRESHOLD ============ -->\n<header class=\"hero\" id=\"threshold\">\n  <div class=\"view\" aria-hidden=\"true\"></div>\n  <div class=\"wall left\" aria-hidden=\"true\"></div>\n  <div class=\"wall right\" aria-hidden=\"true\"></div>\n  <div class=\"lintel\" aria-hidden=\"true\"></div>\n  <div class=\"sill\" aria-hidden=\"true\"></div>\n  <div class=\"grade\" aria-hidden=\"true\"></div>\n\n  <div class=\"hero-inner wrap\">\n    <p class=\"eyebrow load\" style=\"color:rgba(237,234,225,.62)\">Phase of the journey \u00b7 Belonging</p>\n    <h1 class=\"display load l2\">A place within the&nbsp;place.</h1>\n    <p class=\"lede load l3\">Private residences selected for their setting, architecture, privacy and connection to the destination.</p>\n    <div class=\"hero-actions load l4\">\n      <a class=\"action solid\" href=\"#destinations\">Explore private stays <span class=\"mark\">\u2192</span></a>\n      <a class=\"action\" href=\"/begin?mode=stay&src=stay-hero\">Begin a journey <span class=\"mark\">\u2192</span></a>\n    </div>\n  </div>\n\n  <div class=\"hero-ident load l4\" aria-label=\"Stay \u2014 private residences, Whitsundays, Noosa, Tasmania\">\n    <b>STAY</b><br>\n    PRIVATE RESIDENCES<br>\n    WHITSUNDAYS \u00b7 NOOSA \u00b7 TASMANIA\n  </div>\n</header>\n\n<!-- ============ 2 \u00b7 EDITORIAL INTRODUCTION ============ -->\n<section class=\"intro\">\n  <div class=\"wrap split\">\n    <div>\n      <p class=\"eyebrow settle\">Stay</p>\n      <h2 class=\"display settle d1\">Some places are worth staying for.</h2>\n      <p class=\"lede settle d2\">The most memorable residences do more than provide a view. They shape the way a destination is experienced \u2014 through light, landscape, privacy and the rhythm of each day.</p>\n      <p class=\"statement settle d3\">Chosen not only for where they are, but for how they make you feel while you are there.</p>\n    </div>\n\n    <!-- Drawn architectural detail: window elevation framing the landscape -->\n    <figure class=\"window-figure enter d2\">\n      <svg viewBox=\"0 0 560 640\" role=\"img\" aria-label=\"Elevation drawing of a window framing a coastal landscape, with curtain and measured annotations\">\n        <rect x=\"0\" y=\"0\" width=\"560\" height=\"640\" fill=\"#2B2822\"/>\n        <!-- the view held in the frame -->\n        <g>\n          <rect x=\"90\" y=\"80\" width=\"380\" height=\"460\" fill=\"#C3C6BB\"/>\n          <rect x=\"90\" y=\"270\" width=\"380\" height=\"34\" fill=\"#7C8B8F\"/>\n          <rect x=\"90\" y=\"304\" width=\"380\" height=\"236\" fill=\"#D8CFC0\"/>\n          <rect x=\"90\" y=\"304\" width=\"380\" height=\"10\" fill=\"#98A096\" opacity=\".6\"/>\n        </g>\n        <!-- linen curtain, mid-breeze -->\n        <path d=\"M 350 80\n                 C 370 180, 330 260, 356 350\n                 C 378 430, 340 500, 360 540\n                 L 470 540 L 470 80 Z\"\n              fill=\"#E6E0D2\" opacity=\"0.92\"/>\n        <path d=\"M 396 80 C 408 200, 384 330, 402 540\" stroke=\"#C9B295\" stroke-width=\"1.5\" fill=\"none\" opacity=\".7\"/>\n        <path d=\"M 432 80 C 440 190, 420 340, 436 540\" stroke=\"#C9B295\" stroke-width=\"1.5\" fill=\"none\" opacity=\".5\"/>\n        <!-- frame + mullion -->\n        <g stroke=\"#211F1B\" fill=\"none\">\n          <rect x=\"90\" y=\"80\" width=\"380\" height=\"460\" stroke-width=\"10\"/>\n          <line x1=\"90\" y1=\"310\" x2=\"470\" y2=\"310\" stroke-width=\"6\"/>\n        </g>\n        <!-- timber sill -->\n        <rect x=\"74\" y=\"540\" width=\"412\" height=\"16\" fill=\"#8A6F52\"/>\n        <!-- a book left beside the window -->\n        <g>\n          <rect x=\"120\" y=\"524\" width=\"64\" height=\"10\" fill=\"#A9703C\"/>\n          <rect x=\"126\" y=\"516\" width=\"52\" height=\"8\" fill=\"#E6E0D2\"/>\n        </g>\n        <!-- measured annotations -->\n        <g stroke=\"#96938A\" stroke-width=\"1\" opacity=\"0.85\">\n          <line x1=\"90\" y1=\"600\" x2=\"470\" y2=\"600\"/>\n          <line x1=\"90\" y1=\"592\" x2=\"90\" y2=\"608\"/>\n          <line x1=\"470\" y1=\"592\" x2=\"470\" y2=\"608\"/>\n          <line x1=\"34\" y1=\"80\" x2=\"34\" y2=\"540\"/>\n          <line x1=\"26\" y1=\"80\" x2=\"42\" y2=\"80\"/>\n          <line x1=\"26\" y1=\"540\" x2=\"42\" y2=\"540\"/>\n        </g>\n        <text x=\"280\" y=\"622\" text-anchor=\"middle\" font-family=\"'IBM Plex Mono', monospace\" font-size=\"11\" fill=\"#96938A\" letter-spacing=\"2\">OPENING \u00b7 EAST</text>\n        <text x=\"22\" y=\"315\" font-family=\"'IBM Plex Mono', monospace\" font-size=\"11\" fill=\"#96938A\" letter-spacing=\"2\" transform=\"rotate(-90 22 315)\">SILL \u2014 HEAD</text>\n      </svg>\n      <figcaption class=\"fig-caption\">\n        <span class=\"mono-note\">W-02 \u00b7 EAST ELEVATION</span>\n        <span class=\"mono-note\">TIMBER \u00b7 LINEN \u00b7 MORNING LIGHT</span>\n      </figcaption>\n    </figure>\n  </div>\n</section>\n\n<!-- ============ 3 \u00b7 THE ARCHITECTURE OF BELONGING ============ -->\n<section class=\"belonging\" id=\"belonging\">\n  <div class=\"wrap\">\n    <div class=\"belonging-head\">\n      <p class=\"eyebrow settle\">The architecture of belonging</p>\n      <h2 class=\"display settle d1\">A stay, drawn as a sequence of thresholds.</h2>\n    </div>\n\n    <div class=\"plan\" id=\"plan\">\n      <div class=\"plan-line\" aria-hidden=\"true\"><div class=\"pencil\" id=\"pencil\"></div></div>\n\n      <div class=\"space settle\">\n        <div class=\"glyph\" aria-hidden=\"true\">\n          <!-- threshold ticks -->\n          <svg viewBox=\"0 0 56 56\"><g stroke=\"#8A6F52\" stroke-width=\"1.4\" fill=\"none\">\n            <line x1=\"28\" y1=\"6\" x2=\"28\" y2=\"50\"/>\n            <line x1=\"18\" y1=\"14\" x2=\"38\" y2=\"14\"/><line x1=\"18\" y1=\"26\" x2=\"38\" y2=\"26\"/><line x1=\"18\" y1=\"38\" x2=\"38\" y2=\"38\"/>\n          </g></svg>\n        </div>\n        <div><div class=\"sp-name\">Arrive</div><span class=\"sp-anno\">THR-01 \u00b7 APPROACH</span></div>\n        <p class=\"sp-line\">The destination becomes quieter as the door closes behind you.</p>\n      </div>\n\n      <div class=\"space settle\">\n        <div class=\"glyph\" aria-hidden=\"true\">\n          <!-- door swing -->\n          <svg viewBox=\"0 0 56 56\"><g stroke=\"#8A6F52\" stroke-width=\"1.4\" fill=\"none\">\n            <line x1=\"12\" y1=\"46\" x2=\"12\" y2=\"10\"/>\n            <path d=\"M 12 10 A 36 36 0 0 1 48 46\" stroke-dasharray=\"3 4\"/>\n            <line x1=\"12\" y1=\"46\" x2=\"48\" y2=\"46\"/>\n          </g></svg>\n        </div>\n        <div><div class=\"sp-name\">Enter</div><span class=\"sp-anno\">DR-01 \u00b7 SWING 90\u00b0</span></div>\n        <p class=\"sp-line\">Architecture frames the first view.</p>\n      </div>\n\n      <div class=\"space settle\">\n        <div class=\"glyph\" aria-hidden=\"true\">\n          <!-- elevation datum lines -->\n          <svg viewBox=\"0 0 56 56\"><g stroke=\"#8A6F52\" stroke-width=\"1.4\" fill=\"none\">\n            <line x1=\"8\" y1=\"18\" x2=\"48\" y2=\"18\"/><line x1=\"8\" y1=\"30\" x2=\"48\" y2=\"30\"/><line x1=\"8\" y1=\"42\" x2=\"48\" y2=\"42\"/>\n            <line x1=\"8\" y1=\"14\" x2=\"8\" y2=\"22\"/><line x1=\"48\" y1=\"38\" x2=\"48\" y2=\"46\"/>\n          </g></svg>\n        </div>\n        <div><div class=\"sp-name\">Settle</div><span class=\"sp-anno\">RL +0.00 \u00b7 DATUM</span></div>\n        <p class=\"sp-line\">Bags disappear. Time slows.</p>\n      </div>\n\n      <div class=\"space settle\">\n        <div class=\"glyph\" aria-hidden=\"true\">\n          <!-- table in plan -->\n          <svg viewBox=\"0 0 56 56\"><g stroke=\"#8A6F52\" stroke-width=\"1.4\" fill=\"none\">\n            <rect x=\"16\" y=\"20\" width=\"24\" height=\"16\"/>\n            <line x1=\"12\" y1=\"24\" x2=\"12\" y2=\"32\"/><line x1=\"44\" y1=\"24\" x2=\"44\" y2=\"32\"/>\n            <line x1=\"22\" y1=\"14\" x2=\"34\" y2=\"14\"/><line x1=\"22\" y1=\"42\" x2=\"34\" y2=\"42\"/>\n          </g></svg>\n        </div>\n        <div><div class=\"sp-name\">Gather</div><span class=\"sp-anno\">TB-01 \u00b7 SEATS AS NEEDED</span></div>\n        <p class=\"sp-line\">Food, conversation and the day meet around one table.</p>\n      </div>\n\n      <div class=\"space settle\">\n        <div class=\"glyph\" aria-hidden=\"true\">\n          <!-- section hatch: interior meets landscape -->\n          <svg viewBox=\"0 0 56 56\"><g stroke=\"#8A6F52\" stroke-width=\"1.2\" fill=\"none\">\n            <line x1=\"8\" y1=\"40\" x2=\"48\" y2=\"40\"/>\n            <line x1=\"12\" y1=\"40\" x2=\"18\" y2=\"46\"/><line x1=\"20\" y1=\"40\" x2=\"26\" y2=\"46\"/><line x1=\"28\" y1=\"40\" x2=\"34\" y2=\"46\"/><line x1=\"36\" y1=\"40\" x2=\"42\" y2=\"46\"/>\n            <path d=\"M 10 40 C 18 24, 30 18, 46 16\" stroke-dasharray=\"3 4\"/>\n          </g></svg>\n        </div>\n        <div><div class=\"sp-name\">Rest</div><span class=\"sp-anno\">SEC A\u2013A \u00b7 GROUND LINE</span></div>\n        <p class=\"sp-line\">The residence becomes part of the landscape.</p>\n      </div>\n\n      <div class=\"space settle\">\n        <div class=\"glyph\" aria-hidden=\"true\">\n          <!-- door swing, returning inward -->\n          <svg viewBox=\"0 0 56 56\"><g stroke=\"#8A6F52\" stroke-width=\"1.4\" fill=\"none\">\n            <line x1=\"44\" y1=\"46\" x2=\"44\" y2=\"10\"/>\n            <path d=\"M 44 10 A 36 36 0 0 0 8 46\" stroke-dasharray=\"3 4\"/>\n            <line x1=\"8\" y1=\"46\" x2=\"44\" y2=\"46\"/>\n          </g></svg>\n        </div>\n        <div><div class=\"sp-name\">Return</div><span class=\"sp-anno\">DR-01 \u00b7 INWARD</span></div>\n        <p class=\"sp-line\">Each journey out begins and ends here.</p>\n      </div>\n    </div>\n\n    <div class=\"plan-footnote settle\">\n      <a class=\"action quiet\" href=\"/begin?mode=stay&src=stay-belonging\">Begin your stay <span class=\"mark\">\u2192</span></a>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 4 \u00b7 FEATURED DESTINATIONS ============ -->\n<section class=\"dest-chapters\" id=\"destinations\">\n  <div class=\"wrap\">\n    <div class=\"dest-chapters-head\">\n      <p class=\"eyebrow settle\">Destinations</p>\n      <h2 class=\"display settle d1\">Three places. Three ways of belonging.</h2>\n    </div>\n\n    <!-- CMS: destination chapters render from `destination` + relationship graph -->\n\n    <article class=\"dchapter settle\" data-tone=\"hamilton\" data-cms=\"destination\" data-dest=\"whitsundays\">\n      <div class=\"material enter\" aria-hidden=\"true\">\n        <span class=\"m-note\">LIGHT \u00b7 WATER \u00b7 OPENNESS</span>\n      </div>\n      <div>\n        <h3>Hamilton Island</h3>\n        <p class=\"d-essence\">An island residence at the centre of the Whitsundays.</p>\n        <div class=\"themes\">\n          <span>Ocean views</span><span>Private arrival</span><span>Yacht access</span><span>Whitehaven &amp; reef journeys</span><span>Long lunches</span><span>Sunset</span><span>Golf</span><span>Helicopter access</span>\n        </div>\n        <div class=\"services\">AIR \u00b7 SEA \u00b7 STAY \u00b7 EXPERIENCES</div>\n        <a class=\"action\" href=\"/begin?dest=whitsundays&mode=stay&src=stay-dest\">Explore Hamilton Island <span class=\"mark\">\u2192</span></a>\n      </div>\n    </article>\n\n    <article class=\"dchapter settle\" data-tone=\"noosa\" data-cms=\"destination\" data-dest=\"noosa\">\n      <div class=\"material enter\" aria-hidden=\"true\">\n        <span class=\"m-note\">WARMTH \u00b7 RIVER \u00b7 COAST</span>\n      </div>\n      <div>\n        <h3>Noosa</h3>\n        <p class=\"d-essence\">Coast, river and hinterland within one unhurried stay.</p>\n        <div class=\"themes\">\n          <span>Morning ocean swims</span><span>River access</span><span>Private dining</span><span>Wellness</span><span>Hinterland</span><span>Yacht &amp; boat experiences</span><span>Local food</span><span>Sunshine Coast Airport nearby</span>\n        </div>\n        <div class=\"services\">AIR \u00b7 SEA \u00b7 STAY \u00b7 EXPERIENCES</div>\n        <a class=\"action\" href=\"/begin?dest=noosa&mode=stay&src=stay-dest\">Explore Noosa <span class=\"mark\">\u2192</span></a>\n      </div>\n    </article>\n\n    <article class=\"dchapter settle\" data-tone=\"tasmania\" data-cms=\"destination\" data-dest=\"tasmania\">\n      <div class=\"material enter\" aria-hidden=\"true\">\n        <span class=\"m-note\">STONE \u00b7 TIMBER \u00b7 SHADOW \u00b7 FIRELIGHT</span>\n      </div>\n      <div>\n        <h3>Tasmania</h3>\n        <p class=\"d-essence\">Architecture, wilderness and the feeling of being far away.</p>\n        <div class=\"themes\">\n          <span>Firelight</span><span>Cool-climate wine</span><span>Remote coast</span><span>Wilderness</span><span>Private guides</span><span>Chef-led dining</span><span>Aviation access</span><span>Seasonal landscapes</span>\n        </div>\n        <div class=\"services\">AIR \u00b7 STAY \u00b7 EXPERIENCES</div>\n        <a class=\"action\" href=\"/begin?dest=tasmania&mode=stay&src=stay-dest\">Explore Tasmania <span class=\"mark\">\u2192</span></a>\n      </div>\n    </article>\n  </div>\n</section>\n\n<!-- ============ 5 \u00b7 CURATED RESIDENCES ============ -->\n<section class=\"residences\" id=\"residences\">\n  <div class=\"wrap\">\n    <div class=\"residences-head\">\n      <p class=\"eyebrow settle\">Curated residences</p>\n      <h2 class=\"display settle d1\">One residence at a time.</h2>\n      <p class=\"lede settle d2\">A small collection, chosen for setting, character and the role each plays within the wider journey. Final residence allocation depends on availability and journey requirements.</p>\n    </div>\n\n    <!-- CMS: residences render from `residence` schema.\n         commercialRelationship \u00b7 listingStatus \u00b7 availabilityMode \u00b7 specsVerified\n         Bedrooms, capacity and inclusions render only where verified. -->\n\n    <article class=\"residence settle\" data-tone=\"hamilton\" data-cms=\"residence\" data-residence=\"hamilton-island-residence\">\n      <div class=\"res-grid\">\n        <div class=\"res-media enter\">\n          <div class=\"placeholder\"><span>SELECTED RESIDENCE \u00b7 HAMILTON ISLAND<br>MEDIA RENDERS FROM CMS \u00b7 PLACEHOLDER</span></div>\n        </div>\n        <div class=\"res-body\">\n          <p class=\"eyebrow r-dest\">Whitsundays</p>\n          <h3>Hamilton Island Residence</h3>\n          <p class=\"r-essence\">The island at your door; the passage beyond the terrace.</p>\n          <div class=\"res-facts\">\n            <div><div class=\"f-label\">Setting</div><p>Elevated over the water, minutes from the marina and airport.</p></div>\n            <div><div class=\"f-label\">Guest profile</div><p>Families and small groups building an island-and-sea journey.</p></div>\n            <div><div class=\"f-label\">Architectural character</div><p>Open living, limestone and timber, framed ocean views.</p></div>\n            <div><div class=\"f-label\">Ideal journey</div><p>Island Passage \u2014 residence, ALANI and the reef in one course.</p></div>\n          </div>\n          <div class=\"res-with\">\n            <div class=\"f-label\">Best experienced with</div>\n            <ul><li>Yacht charter</li><li>Private chef</li><li>Helicopter arrival</li><li>Reef experience</li></ul>\n          </div>\n          <p class=\"mono-note res-attr\" data-cms-bind=\"residence.attribution\">ATTRIBUTION RENDERS FROM COMMERCIAL RELATIONSHIP \u00b7 AVAILABLE BY ARRANGEMENT</p>\n          <p class=\"mono-note\" data-cms-bind=\"residence.specs\" data-render=\"verified-only\">VERIFIED FACTS RENDER FROM CMS DATA</p>\n          <a class=\"action quiet\" href=\"/begin?dest=whitsundays&mode=stay&residence=hamilton-island-residence&src=stay-residence\">Explore the residence <span class=\"mark\">\u2192</span></a>\n        </div>\n      </div>\n    </article>\n\n    <article class=\"residence settle\" data-tone=\"noosa\" data-cms=\"residence\" data-residence=\"noosa-residence\">\n      <div class=\"res-grid\">\n        <div class=\"res-media enter\">\n          <div class=\"placeholder\"><span>SELECTED RESIDENCE \u00b7 NOOSA<br>MEDIA RENDERS FROM CMS \u00b7 PLACEHOLDER</span></div>\n        </div>\n        <div class=\"res-body\">\n          <p class=\"eyebrow r-dest\">Noosa</p>\n          <h3>Noosa Residence</h3>\n          <p class=\"r-essence\">River light in the morning; the coast by afternoon.</p>\n          <div class=\"res-facts\">\n            <div><div class=\"f-label\">Setting</div><p>Between river and headland, an easy transfer from Sunshine Coast Airport.</p></div>\n            <div><div class=\"f-label\">Guest profile</div><p>Couples and families settling into an unhurried coastal rhythm.</p></div>\n            <div><div class=\"f-label\">Architectural character</div><p>Relaxed natural materials, open to the breeze and the water.</p></div>\n            <div><div class=\"f-label\">Ideal journey</div><p>Coastal Interlude \u2014 river charter, wellness and private dining.</p></div>\n          </div>\n          <div class=\"res-with\">\n            <div class=\"f-label\">Best experienced with</div>\n            <ul><li>River or coastal charter</li><li>Private dining</li><li>Wellness</li><li>Hinterland day</li></ul>\n          </div>\n          <p class=\"mono-note res-attr\" data-cms-bind=\"residence.attribution\">ATTRIBUTION RENDERS FROM COMMERCIAL RELATIONSHIP \u00b7 AVAILABLE BY ARRANGEMENT</p>\n          <p class=\"mono-note\" data-cms-bind=\"residence.specs\" data-render=\"verified-only\">VERIFIED FACTS RENDER FROM CMS DATA</p>\n          <a class=\"action quiet\" href=\"/begin?dest=noosa&mode=stay&residence=noosa-residence&src=stay-residence\">Explore the residence <span class=\"mark\">\u2192</span></a>\n        </div>\n      </div>\n    </article>\n\n    <article class=\"residence settle\" data-tone=\"tasmania\" data-cms=\"residence\" data-residence=\"tasmania-residence\">\n      <div class=\"res-grid\">\n        <div class=\"res-media enter\">\n          <div class=\"placeholder\"><span>SELECTED RESIDENCE \u00b7 TASMANIA<br>MEDIA RENDERS FROM CMS \u00b7 PLACEHOLDER</span></div>\n        </div>\n        <div class=\"res-body\">\n          <p class=\"eyebrow r-dest\">Tasmania</p>\n          <h3>Tasmanian Residence</h3>\n          <p class=\"r-essence\">Stone and timber holding warmth against the weather.</p>\n          <div class=\"res-facts\">\n            <div><div class=\"f-label\">Setting</div><p>Within reach of wine country and the wild coast, arrived by air.</p></div>\n            <div><div class=\"f-label\">Guest profile</div><p>Travellers seeking distance, texture and the southern table.</p></div>\n            <div><div class=\"f-label\">Architectural character</div><p>Grounded forms, deep windows, firelight after dark.</p></div>\n            <div><div class=\"f-label\">Ideal journey</div><p>Southern Latitude \u2014 wine, wilderness and chef-led dining.</p></div>\n          </div>\n          <div class=\"res-with\">\n            <div class=\"f-label\">Best experienced with</div>\n            <ul><li>Private guide</li><li>Wine experience</li><li>Chef-led dining</li><li>Wilderness access</li></ul>\n          </div>\n          <p class=\"mono-note res-attr\" data-cms-bind=\"residence.attribution\">ATTRIBUTION RENDERS FROM COMMERCIAL RELATIONSHIP \u00b7 AVAILABLE BY ARRANGEMENT</p>\n          <p class=\"mono-note\" data-cms-bind=\"residence.specs\" data-render=\"verified-only\">VERIFIED FACTS RENDER FROM CMS DATA</p>\n          <a class=\"action quiet\" href=\"/begin?dest=tasmania&mode=stay&residence=tasmania-residence&src=stay-residence\">Explore the residence <span class=\"mark\">\u2192</span></a>\n        </div>\n      </div>\n    </article>\n  </div>\n</section>\n\n<!-- ============ 6 \u00b7 THE RHYTHM OF A STAY ============ -->\n<section class=\"rhythm\" id=\"rhythm\">\n  <div class=\"wrap\">\n    <div class=\"rhythm-head\">\n      <p class=\"eyebrow settle\">The rhythm of a stay</p>\n      <h2 class=\"display settle d1\">One day, unscheduled.</h2>\n    </div>\n\n    <div class=\"day\">\n      <div class=\"moment settle\">\n        <div class=\"m-time\">Early</div>\n        <div><div class=\"m-line\">Coffee before the house wakes.</div>\n        <span class=\"m-detail\">Bare feet on stone. A door left open to the breeze.</span></div>\n      </div>\n      <div class=\"moment settle\">\n        <div class=\"m-time\">Morning</div>\n        <div><div class=\"m-line\">The destination begins outside the door.</div>\n        <span class=\"m-detail\">Towels after the ocean. Wet swimwear drying on the rail.</span></div>\n      </div>\n      <div class=\"moment settle\">\n        <div class=\"m-time\">Midday</div>\n        <div><div class=\"m-line\">Lunch returns to the table.</div>\n        <span class=\"m-detail\">Produce being prepared. A table set slowly, without occasion.</span></div>\n      </div>\n      <div class=\"moment settle\">\n        <div class=\"m-time\">Afternoon</div>\n        <div><div class=\"m-line\">The residence becomes quiet again.</div>\n        <span class=\"m-detail\">A book beside a window. Light moving across timber.</span></div>\n      </div>\n      <div class=\"moment settle\">\n        <div class=\"m-time\">Evening</div>\n        <div><div class=\"m-line\">Fire, water, wine or sunset.</div>\n        <span class=\"m-detail\">A fire being lit. The day settling into the landscape.</span></div>\n      </div>\n      <div class=\"moment settle\">\n        <div class=\"m-time\">Night</div>\n        <div><div class=\"m-line\">Nothing scheduled.</div>\n        <span class=\"m-detail\">Children asleep. The house holding its quiet.</span></div>\n      </div>\n    </div>\n\n    <div class=\"rhythm-footnote settle\">\n      <span class=\"mono-note\">THE RESIDENCE, INHABITED \u00b7 NOT STAGED</span>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 7 \u00b7 CONNECTED JOURNEYS ============ -->\n<section class=\"journeys\" id=\"journeys\">\n  <div class=\"wrap\">\n    <div class=\"journeys-head\">\n      <p class=\"eyebrow settle\">Connected journeys</p>\n      <h2 class=\"display settle d1\">The residence at the centre of the course.</h2>\n    </div>\n\n    <!-- CMS: journeys render from `journey` + `journeyLeg`; relationships CMS-authored only -->\n    <div class=\"journey-grid\">\n\n      <article class=\"journey settle\" data-cms=\"journey\" data-journey=\"island-passage\">\n        <div class=\"j-kicker eyebrow\">Journey 01</div>\n        <h3>Island Passage</h3>\n        <div class=\"j-course\">\n          <div class=\"j-step\"><div class=\"s-kind\">Depart</div><div class=\"s-text\">Brisbane.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Air</div><div class=\"s-text\">Private aircraft to Hamilton Island.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Stay</div><div class=\"s-text\">Hamilton Island residence.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Sea</div><div class=\"s-text\">ALANI through the passage.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Experience</div><div class=\"s-text\">Whitehaven Beach \u00b7 private chef.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Return</div><div class=\"s-text\">Helicopter return.</div></div>\n        </div>\n        <div class=\"j-actions\">\n          <a class=\"action quiet\" href=\"/begin?journey=island-passage&src=stay-journeys\">Explore the journey <span class=\"mark\">\u2192</span></a>\n          <a class=\"action quiet\" href=\"/begin?journey=island-passage&shape=1&src=stay-journeys\">Shape this journey <span class=\"mark\">\u2192</span></a>\n        </div>\n      </article>\n\n      <article class=\"journey settle d1\" data-cms=\"journey\" data-journey=\"southern-latitude\">\n        <div class=\"j-kicker eyebrow\">Journey 02</div>\n        <h3>Southern Latitude</h3>\n        <div class=\"j-course\">\n          <div class=\"j-step\"><div class=\"s-kind\">Depart</div><div class=\"s-text\">Melbourne.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Air</div><div class=\"s-text\">Private aircraft across the strait.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Stay</div><div class=\"s-text\">Tasmanian residence.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Experience</div><div class=\"s-text\">Wine region \u00b7 private guide.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Experience</div><div class=\"s-text\">Wilderness dining.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Return</div><div class=\"s-text\">Northbound, rested.</div></div>\n        </div>\n        <div class=\"j-actions\">\n          <a class=\"action quiet\" href=\"/begin?journey=southern-latitude&src=stay-journeys\">Explore the journey <span class=\"mark\">\u2192</span></a>\n          <a class=\"action quiet\" href=\"/begin?journey=southern-latitude&shape=1&src=stay-journeys\">Shape this journey <span class=\"mark\">\u2192</span></a>\n        </div>\n      </article>\n\n      <article class=\"journey settle d2\" data-cms=\"journey\" data-journey=\"coastal-interlude\">\n        <div class=\"j-kicker eyebrow\">Journey 03</div>\n        <h3>Coastal Interlude</h3>\n        <div class=\"j-course\">\n          <div class=\"j-step\"><div class=\"s-kind\">Arrive</div><div class=\"s-text\">Sunshine Coast Airport.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Transfer</div><div class=\"s-text\">Private transfer to Noosa.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Stay</div><div class=\"s-text\">Noosa residence.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Sea</div><div class=\"s-text\">River or coastal charter.</div></div>\n          <div class=\"j-step\"><div class=\"s-kind\">Experience</div><div class=\"s-text\">Wellness \u00b7 private dining.</div></div>\n        </div>\n        <div class=\"j-actions\">\n          <a class=\"action quiet\" href=\"/begin?journey=coastal-interlude&src=stay-journeys\">Explore the journey <span class=\"mark\">\u2192</span></a>\n          <a class=\"action quiet\" href=\"/begin?journey=coastal-interlude&shape=1&src=stay-journeys\">Shape this journey <span class=\"mark\">\u2192</span></a>\n        </div>\n      </article>\n\n    </div>\n  </div>\n</section>\n\n<!-- ============ 8 \u00b7 PRIVATE SERVICES ============ -->\n<section class=\"services\" id=\"services\">\n  <div class=\"wrap split\">\n    <div>\n      <p class=\"eyebrow settle\">Private services</p>\n      <h2 class=\"display settle d1\">Everything the stay needs. Nothing it does not.</h2>\n      <p class=\"lede settle d2\">Services are arranged around the residence, the destination and the way you prefer to travel.</p>\n      <p class=\"mono-note caveat settle d3\">ALL SERVICES SUBJECT TO DESTINATION, PROVIDER AND AVAILABILITY</p>\n    </div>\n    <div class=\"service-list settle d1\">\n      <div class=\"service-row\"><span>Private chef</span><span class=\"s-note\">By arrangement</span></div>\n      <div class=\"service-row\"><span>Butler or host</span><span class=\"s-note\">By arrangement</span></div>\n      <div class=\"service-row\"><span>Housekeeping</span><span class=\"s-note\">Per residence</span></div>\n      <div class=\"service-row\"><span>Provisioning</span><span class=\"s-note\">Before arrival</span></div>\n      <div class=\"service-row\"><span>Airport &amp; helipad transfers</span><span class=\"s-note\">Coordinated</span></div>\n      <div class=\"service-row\"><span>Yacht coordination</span><span class=\"s-note\">With SEA</span></div>\n      <div class=\"service-row\"><span>Wellness</span><span class=\"s-note\">In residence</span></div>\n      <div class=\"service-row\"><span>Childcare</span><span class=\"s-note\">By arrangement</span></div>\n      <div class=\"service-row\"><span>Private guide</span><span class=\"s-note\">Per destination</span></div>\n      <div class=\"service-row\"><span>Wine &amp; food experiences</span><span class=\"s-note\">Per destination</span></div>\n      <div class=\"service-row\"><span>Security &amp; discretion</span><span class=\"s-note\">Where required</span></div>\n      <div class=\"service-row\"><span>Event preparation</span><span class=\"s-note\">By arrangement</span></div>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 9 \u00b7 WHY WAYPOINT \u2014 BEHIND THE STAY ============ -->\n<section class=\"dark why\" id=\"why\">\n  <div class=\"wrap\">\n    <p class=\"eyebrow settle\">Behind the stay</p>\n    <h2 class=\"display settle d1\">Privacy is considered before arrival.</h2>\n\n    <div class=\"principles\">\n      <div class=\"principle settle\">\n        <div class=\"p-code\">Selected with purpose</div>\n        <p>Residences are chosen for their setting, character and role within the wider journey.</p>\n      </div>\n      <div class=\"principle settle d1\">\n        <div class=\"p-code\">One relationship</div>\n        <p>Air, residence, yacht and experience are coordinated through one point of contact.</p>\n      </div>\n      <div class=\"principle settle d2\">\n        <div class=\"p-code\">Local connection</div>\n        <p>Trusted owners, managers and destination partners support each stay.</p>\n      </div>\n      <div class=\"principle settle d3\">\n        <div class=\"p-code\">Human oversight</div>\n        <p>Every request is personally reviewed rather than automatically confirmed.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- ============ 10/11 \u00b7 BEGIN YOUR STAY ============ -->\n<section class=\"begin\" id=\"begin\">\n  <div class=\"wrap\">\n    <p class=\"eyebrow settle\" style=\"color:rgba(237,234,225,.62)\">Begin</p>\n    <h2 class=\"display settle d1\">Where will you return to?</h2>\n    <p class=\"lede settle d2\">Tell us where you are drawn to, and we will begin shaping the stay \u2014 and the journey around it.</p>\n    <div class=\"begin-actions settle d3\">\n      <a class=\"action solid\" href=\"/begin?mode=stay&src=stay-begin\">Begin your stay <span class=\"mark\">\u2192</span></a>\n      <a class=\"action\" href=\"/begin?mode=stay&concierge=1&src=stay-begin\">Speak with our concierge <span class=\"mark\">\u2192</span></a>\n    </div>\n    <div class=\"closing settle d3\">\n      <span class=\"mono-note\">AIR \u00b7 SEA \u00b7 STAY \u2014 ONE CONSIDERED JOURNEY</span>\n    </div>\n  </div>\n</section>\n\n<!-- ============ FOOTER ============ -->\n<footer class=\"footer dark\">\n  <div class=\"wrap\">\n    <div class=\"footer-top\">\n      <div>\n        <div class=\"wordmark\">WAYPOINT &amp; Co.<span>SEA \u00b7 STAY \u00b7 AIR</span></div>\n      </div>\n      <div>\n        <h4>Journey</h4>\n        <ul>\n          <li><a href=\"/sea\">Sea</a></li>\n          <li><a href=\"/stay\">Stay</a></li>\n          <li><a href=\"/air\">Air</a></li>\n          <li><a href=\"/journeys\">Journeys</a></li>\n        </ul>\n      </div>\n      <div>\n        <h4>Stay</h4>\n        <ul>\n          <li><a href=\"#destinations\">Destinations</a></li>\n          <li><a href=\"#residences\">Residences</a></li>\n          <li><a href=\"#services\">Private services</a></li>\n          <li><a href=\"#journeys\">Connected journeys</a></li>\n        </ul>\n      </div>\n      <div>\n        <h4>Company</h4>\n        <ul>\n          <li><a href=\"/about\">About</a></li>\n          <li><a href=\"/contact\">Contact</a></li>\n          <li><a href=\"/terms\">Terms</a></li>\n          <li><a href=\"/privacy\">Privacy</a></li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"footer-bottom\">\n      <span class=\"mono-note\">STAY \u00b7 PRIVATE RESIDENCES \u00b7 WHITSUNDAYS \u00b7 NOOSA \u00b7 TASMANIA</span>\n      <span class=\"mono-note\">\u00a9 WAYPOINT &amp; CO.</span>\n    </div>\n  </div>\n</footer>";
const JS = "(function(){\n  const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;\n\n  /* ---- nav state ---- */\n  const nav = document.getElementById('nav');\n  const onScrollNav = () => nav.classList.toggle('scrolled', window.scrollY > 40);\n  onScrollNav();\n  window.addEventListener('scroll', onScrollNav, { passive: true });\n\n  /* ---- inward + settle reveals ---- */\n  const revealEls = document.querySelectorAll('.enter, .settle');\n  if ('IntersectionObserver' in window && !reduced){\n    const io = new IntersectionObserver((entries) => {\n      entries.forEach(e => {\n        if (e.isIntersecting){ e.target.classList.add('in'); io.unobserve(e.target); }\n      });\n    }, { threshold: 0.15, rootMargin: '0px 0px -6% 0px' });\n    revealEls.forEach(el => io.observe(el));\n  } else {\n    revealEls.forEach(el => el.classList.add('in'));\n  }\n\n  /* ---- architecture of belonging: pencil line draws with scroll ---- */\n  const plan = document.getElementById('plan');\n  const pencil = document.getElementById('pencil');\n  if (plan && pencil && !reduced){\n    const draw = () => {\n      const r = plan.getBoundingClientRect();\n      const vh = window.innerHeight;\n      const start = vh * 0.82;\n      const total = r.height + (start - vh * 0.3);\n      const travelled = Math.min(Math.max(start - r.top, 0), total);\n      pencil.style.height = (travelled / total * 100).toFixed(2) + '%';\n    };\n    draw();\n    window.addEventListener('scroll', draw, { passive: true });\n    window.addEventListener('resize', draw);\n  }\n\n  /* ---- add STAY to journey (session state only) ---- */\n  const addStay = document.getElementById('addStay'); if(!addStay){return;}\n  const label = addStay.querySelector('.label');\n  let added = false; // joins the visitor's living plotted course via the Journey Engine session\n  const showFrom = () => addStay.classList.toggle('visible', window.scrollY > window.innerHeight * 0.7);\n  showFrom();\n  window.addEventListener('scroll', showFrom, { passive: true });\n  addStay.addEventListener('click', () => {\n    added = !added;\n    addStay.classList.toggle('added', added);\n    addStay.setAttribute('aria-pressed', added ? 'true' : 'false');\n    label.textContent = added ? 'STAY added to journey' : 'Add STAY to journey';\n    /* Journey Engine hook: window.WaypointJourney?.add({ mode: 'stay', src: 'stay-page' }) */\n  });\n})();";

export default function StayPage() {
  useEffect(() => {
    try { new Function(JS)(); } catch (e) { console.error("page script:", e); }
  }, []);
  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: CSS }} />
      <div dangerouslySetInnerHTML={{ __html: HTML }} />
    </>
  );
}
